sys_script_include.script:
var IDPAWSConnector = Class.create();
IDPAWSConnector.prototype = {
    initialize: function() {
        this.accessKey = gs.getProperty('x_12345.idp.aws.access_key');
        this.secretKey = gs.getProperty('x_12345.idp.aws.secret_key');
        this.region = gs.getProperty('x_12345.idp.aws.region');
    },

    fetchData: function(entityId) {
        try {
            var url = 'https://ec2.' + this.region + '.amazonaws.com/?Action=DescribeInstances&InstanceId.1=' + entityId;

            var request = new sn_ws.RESTMessageV2();
            request.setEndpoint(url);
            request.setHttpMethod('GET');
            request.setRequestHeader('X-Amz-Date', new GlideDateTime().getDisplayValue());
            request.setRequestHeader('Authorization', 'AWS4-HMAC-SHA256 Credential=' + this.accessKey);

            var response = request.execute();
            var responseBody = response.getBody();

            if (response.getStatusCode() == 200) {
                return this.parseAWSResponse(responseBody);
            }

            return null;
        } catch (ex) {
            gs.error('IDPAWSConnector.fetchData failed: ' + ex.getMessage());
            return null;
        }
    },

    parseAWSResponse: function(xml) {
        try {
            var parser = new XMLParser();
            var doc = parser.parse(xml);
            return doc;
        } catch (ex) {
            gs.error('IDPAWSConnector.parseAWSResponse failed: ' + ex.getMessage());
            return null;
        }
    },

    getEC2Instances: function() {
        try {
            var url = 'https://ec2.' + this.region + '.amazonaws.com/?Action=DescribeInstances';

            var request = new sn_ws.RESTMessageV2();
            request.setEndpoint(url);
            request.setHttpMethod('GET');
            request.setRequestHeader('X-Amz-Date', new GlideDateTime().getDisplayValue());
            request.setRequestHeader('Authorization', 'AWS4-HMAC-SHA256 Credential=' + this.accessKey);

            var response = request.execute();
            var responseBody = response.getBody();

            if (response.getStatusCode() == 200) {
                return this.parseAWSResponse(responseBody);
            }

            return [];
        } catch (ex) {
            gs.error('IDPAWSConnector.getEC2Instances failed: ' + ex.getMessage());
            return [];
        }
    },

    type: 'IDPAWSConnector'
};
